package com.example.eventstreaming.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import java.util.UUID;

@Service
public class EventProducer {

    private final KafkaTemplate<String, String> kafkaTemplate;

    @Value("${app.kafka.topic:events}")
    private String topic;

    public EventProducer(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publish(String eventPayload) {
        String key = UUID.randomUUID().toString();
        kafkaTemplate.send(topic, key, eventPayload);
    }
}

package com.example.eventstreaming.consumer;

import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    @KafkaListener(topics = "${app.kafka.topic:events}", groupId = "${app.kafka.consumer.group-id:event-streaming-group}")
    public void onMessage(ConsumerRecord<String, String> record) {
        String key = record.key();
        String payload = record.value();
        System.out.println("Consumed event key=" + key + " payload=" + payload + " topic=" + record.topic() + " partition=" + record.partition() + " offset=" + record.offset());
    }
}

package com.example.eventstreaming.web;

import com.example.eventstreaming.service.EventProducer;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducer producer;

    public EventController(EventProducer producer) {
        this.producer = producer;
    }

    @PostMapping
    public ResponseEntity<Void> publish(@RequestBody String payload) {
        producer.publish(payload);
        return ResponseEntity.accepted().build();
    }
}

